   489→  logic: string;
   490→  notes: string;
   491→}
   492→
   493→interface AttributeRelevanceMatrix {
   494→  _roles_legend: {
   495→    CORE: string;
   496→    PRIMARY_BOOST: string;
   497→    SECONDARY_BOOST: string;
   498→    DISAMBIGUATOR: string;
   499→    FILTER: string;
   500→    STRUCTURAL: string;
   501→    DERIVED_LINK: string;
   502→    NEUTRAL: string;
   503→  };
   504→  [category: string]:
   505→    | {
   506→        category_roles: Record<string, AttributeRole>;
   507→        subtypes?: Record<
   508→          string,
   509→          {
   510→            roles: Record<string, AttributeRole>;
   511→          }
   512→        >;
   513→      }
   514→    | any; // Allow for _roles_legend
   515→}
   516→
   517→type AttributeRole =
   518→  | 'CORE'
   519→  | 'PRIMARY_BOOST'
   520→  | 'SECONDARY_BOOST'
   521→  | 'DISAMBIGUATOR'
   522→  | 'FILTER'
   523→  | 'STRUCTURAL'
   524→  | 'DERIVED_LINK'
   525→  | 'NEUTRAL';
   526→
   527→interface AIPromptSystem {
   528→  feature_extraction: {
   529→    system_prompt: string[];
   530→    user_prompt: string[];
   531→  };
   532→  final_classification: {
   533→    system_prompt: string[];
   534→    user_prompt: string[];
   535→  };
   536→}
   537→
   538→interface JSONSchema {
   539→  type: string;
   540→  properties: Record<string, any>;
   541→  required: string[];
   542→}
   543→
   544→interface CompiledRule {
   545→  category: string;
   546→  subtype: string;
   547→  tier: string;
   548→  pattern: RegExp;
   549→  weight: number;
   550→}
   551→
   552→interface AttributeInfluenceMatrix {
   553→  [category: string]: {
   554→    [attribute: string]: {
   555→      role: AttributeRole;
   556→      bonus: number;
   557→      cap: number;
   558→    };
   559→  };
   560→}
   561→```
   562→
   563→### Digest Generation Entities
   564→
   565→New entities for HTML email digest generation.
   566→
   567→```typescript
   568→interface EmailDigest {
   569→  id: string; // UUID
   570→  generatedAt: Date;
   571→  digestType: 'daily' | 'weekly' | 'on_demand';
   572→  recipientEmail: string;
   573→
   574→  // Content structure
   575→  categories: DigestCategory[];
   576→  totalEmailCount: number;
   577→  dateRange: {
   578→    start: Date;
   579→    end: Date;
   580→  };
   581→
   582→  // Template and delivery
   583→  templateUsed: string;
   584→  htmlContent: string;
   585→  deliveryStatus: 'pending' | 'sent' | 'failed';
   586→  deliveredAt?: Date;
   587→  deliveryError?: string;
   588→}
   589→
   590→interface DigestCategory {
   591→  categoryName: string;
   592→  emailCount: number;
   593→  emails: DigestEmail[];
   594→  priority: number; // Display order
   595→
   596→  // Template data
   597→  templateData: object; // Handlebars template context
   598→  customSummary?: string; // Optional human-readable summary
   599→}
   600→
   601→interface DigestEmail {
   602→  emailId: string;
   603→  subject: string;
   604→  from: string;
   605→  date: Date;
   606→  snippet: string; // First 150 chars of body
   607→
   608→  // Classification metadata
   609→  confidence: number;
   610→  categories: string[];
   611→  urgency: string;
   612→
   613→  // Digest-specific
   614→  includeFullContent: boolean;
   615→  customHighlights: string[]; // Key extracted information
   616→}
   617→```
   618→
   619→## Enhanced Relationships
   620→
   621→### Core Processing Flow
   622→
   623→```
   624→EmailMessage 1:1 EmailClassification
   625→EmailClassification 1:1 ExplainabilityTrace
   626→EmailClassification 1:1 ScoreBreakdown
   627→EmailClassification 1:1 AttributeContext
   628→EmailClassification N:1 ClassificationSession
   629→```
   630→
   631→### Configuration and Audit
   632→
   633→```
   634→ClassificationSession 1:1 CategoryConfiguration (snapshot)
   635→EmailClassification N:M CategoryDefinition (through categories)
   636→ExplainabilityTrace 1:N AttributeInfluenceApplication
   637→```
   638→
   639→### Digest Generation
   640→
   641→```
   642→EmailDigest 1:N DigestCategory
   643→DigestCategory 1:N DigestEmail
   644→DigestEmail N:1 EmailMessage
   645→DigestEmail N:1 EmailClassification
   646→```
   647→
   648→## Performance Optimizations
   649→
   650→### Database Indexes (Enhanced)
   651→
   652→```sql
   653→-- Batch processing optimization
   654→CREATE INDEX idx_email_processing_batch ON email_message(processing_batch, processing_priority);
   655→
   656→-- Parallel processing queries
   657→CREATE INDEX idx_classification_session_performance ON classification_session(processing_mode, batch_size);
   658→
   659→-- Configuration versioning
   660→CREATE INDEX idx_classification_config_version ON email_classification(session_id, config_version);
   661→
   662→-- Digest generation
   663→CREATE INDEX idx_email_processed_date ON email_message(processed_at) WHERE is_processed = true;
   664→CREATE INDEX idx_classification_primary_category ON email_classification(primary_category, processed_at);
   665→```
   666→
   667→### Batch Operations
   668→
   669→```typescript
   670→// Optimized for parallel processing
   671→interface BatchOperation {
   672→  batchId: string;
   673→  operationType: 'classification' | 'persistence' | 'digest_generation';
   674→  itemCount: number;
   675→  parallelChunks: number;
   676→  retryPolicy: RetryPolicy;
   677→}
   678→```
   679→
   680→## Migration Considerations
   681→
   682→### Schema Preservation
   683→
   684→- All existing audit trail tables preserved
   685→- Enhanced with parallel processing metadata
   686→- Maintains data integrity and auditability
   687→
   688→### Data Migration Path
   689→
   690→1. **Phase 1**: Add new columns to existing tables
   691→2. **Phase 2**: Populate parallel processing metadata
   692→3. **Phase 3**: Add new digest generation tables
   693→4. **Phase 4**: Add performance monitoring tables
   694→
   695→### Parallel Execution Support
   696→
   697→- Batch processing identifiers
   698→- Stage execution timing metadata
   699→- Dependency tracking between classification stages
   700→- Configuration snapshot versioning for reproducibility
   701→
   702→This data model preserves all sophisticated classification capabilities while optimizing for the new parallel processing architecture and enhanced auditability requirements.
   703→

