    });

    it('should not include delivered timestamp on failure', async () => {
      mockTransporter.sendMail.mockRejectedValue(new Error('Delivery failed'));

      const result = await service.sendDigest(sampleDigest);

      expect(result.deliveredAt).toBeUndefined();
    });
  });
