/**
 * Email Delivery Service (T047) - SMTP Implementation
 *
 * Handles SMTP email delivery with nodemailer:
 * - SMTP connection configuration and verification
 * - Email formatting (from, to, subject, HTML/plain text)
 * - Delivery status tracking with retry logic
 * - Error recovery and detailed error reporting
 *
 * Integrates with:
 * - DigestGenerator (T046) for EmailDigest input
 * - nodemailer for SMTP transport
 */

import nodemailer, { type Transporter, type SendMailOptions, type SentMessageInfo } from 'nodemailer';
import type { EmailDigest } from '../types/email-digest';

/**
 * SMTP configuration for email delivery
 */
export interface SMTPConfig {
  /** SMTP server hostname */
  host: string;
  /** SMTP server port (587 for TLS, 465 for SSL) */
  port: number;
  /** Use TLS/SSL connection */
  secure: boolean;
  /** Authentication credentials */
  auth: {
    /** SMTP username */
    user: string;
    /** SMTP password or app password */
    pass: string;
  };
}

/**
 * Optional delivery configuration
 */
export interface DeliveryOptions {
  /** Override recipient email address */
  overrideRecipient?: string;
  /** From email address (defaults to SMTP auth user) */
  fromAddress?: string;
  /** From display name */
  fromName?: string;
  /** Custom subject line (overrides generated subject) */
  subject?: string;
  /** Maximum retry attempts on failure */
  maxRetries?: number;
  /** Delay between retries in milliseconds */
  retryDelayMs?: number;
}

/**
 * Delivery result with status tracking
 */
export interface DeliveryResult {
  /** Digest ID reference */
  digestId: string;
  /** Delivery timestamp (if successful) */
  deliveredAt?: Date;
  /** Recipient email address */
  recipientEmail: string;
  /** Delivery status */
  deliveryStatus: 'sent' | 'failed';
  /** SMTP message ID (if successful) */
  messageId?: string;
  /** Delivery time in milliseconds */
  deliveryTimeMs: number;
  /** Error message (if failed) */
  error?: string;
  /** Number of retry attempts made */
  retryCount: number;
}

/**
 * Email Delivery Service Implementation
 *
 * Provides SMTP email delivery for digest generation
 */
export class EmailDeliveryService {
  private readonly transporter: Transporter;
  private readonly config: SMTPConfig;
  private readonly defaultFromAddress: string;

  /**
   * Initialize EmailDeliveryService with SMTP configuration
   *
   * @param config - SMTP server configuration
   * @throws {Error} If SMTP configuration is invalid
   */
  constructor(config: SMTPConfig) {
    this.validateConfig(config);
    this.config = config;
    this.defaultFromAddress = config.auth.user;

    // Create nodemailer transporter
    this.transporter = nodemailer.createTransport({
      host: config.host,
      port: config.port,
      secure: config.secure,
      auth: {
        user: config.auth.user,
        pass: config.auth.pass,
      },
    });
  }

  /**
   * Verify SMTP connection
   *
   * @returns true if connection successful, false otherwise
   */
  async verifyConnection(): Promise<boolean> {
    try {
      await this.transporter.verify();
      return true;
    } catch {
      return false;
    }
  }

  /**
   * Send digest email via SMTP
   *
   * @param digest - Email digest to send
   * @param options - Optional delivery configuration
   * @returns Delivery result with status and metadata
   */
  async sendDigest(digest: EmailDigest, options?: DeliveryOptions): Promise<DeliveryResult> {
    const startTime = Date.now();

    // Validate digest content
    const validationError = this.validateDigest(digest);
    if (validationError) {
      return this.createFailedResult(digest, validationError, startTime, 0);
    }

    // Prepare email options
    const recipientEmail = options?.overrideRecipient || digest.recipientEmail;
    const fromAddress = options?.fromAddress || this.defaultFromAddress;
    const fromName = options?.fromName || 'Email Digest Service';
    const subject = options?.subject || this.formatSubject(digest);

    const mailOptions: SendMailOptions = {
      from: fromName ? `"${fromName}" <${fromAddress}>` : fromAddress,
      to: recipientEmail,
      subject,
      html: digest.htmlContent,
      text: this.generatePlainText(digest.htmlContent),
    };

    // Attempt delivery with retries
    const maxRetries = options?.maxRetries ?? 2;
    const retryDelayMs = options?.retryDelayMs ?? 1000;

    let lastError: Error | undefined;
    for (let attempt = 0; attempt <= maxRetries; attempt++) {
      try {
        const info: SentMessageInfo = await this.transporter.sendMail(mailOptions);
        const deliveryTimeMs = Date.now() - startTime;

        return {
          digestId: digest.id,
          deliveredAt: new Date(),
          recipientEmail,
          deliveryStatus: 'sent',
          messageId: info.messageId,
          deliveryTimeMs,
          retryCount: attempt,
        };
      } catch (error) {
        lastError = error instanceof Error ? error : new Error(String(error));

        // If not the last attempt, wait before retry
        if (attempt < maxRetries) {
          await this.sleep(retryDelayMs);
        }
      }
    }

    // All attempts failed
    const deliveryTimeMs = Date.now() - startTime;
    return {
      digestId: digest.id,
      recipientEmail,
      deliveryStatus: 'failed',
      deliveryTimeMs,
      error: lastError?.message || 'Unknown delivery error',
      retryCount: maxRetries,
    };
  }

  /**
   * Send test email without actual delivery (preview mode)
   *
   * @param digest - Email digest to preview
   * @returns Delivery result indicating test mode
   */
  async sendTestEmail(digest: EmailDigest): Promise<DeliveryResult> {
    const startTime = Date.now();

    // Simulate processing delay
    await this.sleep(10);

    const deliveryTimeMs = Date.now() - startTime;

    return {
      digestId: digest.id,
      deliveredAt: new Date(),
      recipientEmail: digest.recipientEmail,
      deliveryStatus: 'sent',
      messageId: `<test-mode-${digest.id}@localhost>`,
      deliveryTimeMs,
      error: 'Test mode - email not actually sent',
      retryCount: 0,
    };
  }

  /**
   * Format subject line for digest email
   *
   * @param digest - Email digest
   * @returns Formatted subject line
   */
  formatSubject(digest: EmailDigest): string {
    const digestTypeLabel = this.getDigestTypeLabel(digest.digestType);
    const totalEmails = digest.totalEmailCount;
    const dateStr = digest.generatedAt.toISOString().split('T')[0]; // YYYY-MM-DD

    // Count urgent emails
    const urgentCount = digest.categories.reduce(
      (sum, cat) => sum + cat.categoryMetadata.urgencyDistribution.high,
      0
    );

    const urgentSuffix = urgentCount > 0 ? ` (${urgentCount} urgent)` : '';

    return `${digestTypeLabel} - ${totalEmails} email${totalEmails === 1 ? '' : 's'}${urgentSuffix} - ${dateStr}`;
  }

  /**
   * Close SMTP connection
   */
  async close(): Promise<void> {
    try {
      this.transporter.close();
    } catch {
      // Ignore close errors
    }
  }

  /**
   * Validate SMTP configuration
   */
  private validateConfig(config: SMTPConfig): void {
    if (!config.host || config.host.trim() === '') {
      throw new Error('Invalid SMTP configuration: host is required');
    }

    if (!config.port || config.port < 1 || config.port > 65535) {
      throw new Error('Invalid SMTP configuration: port must be between 1 and 65535');
    }

    if (!config.auth || !config.auth.user || !config.auth.pass) {
      throw new Error('Invalid SMTP configuration: auth credentials are required');
    }
  }

  /**
   * Validate digest content before sending
   */
  private validateDigest(digest: EmailDigest): string | null {
    // Validate recipient email format
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(digest.recipientEmail)) {
      return 'Invalid recipient email format';
    }

    // Validate HTML content
    if (!digest.htmlContent || digest.htmlContent.trim() === '') {
      return 'HTML content is required';
    }

    return null;
  }

  /**
   * Create failed delivery result
   */
  private createFailedResult(
    digest: EmailDigest,
    error: string,
    startTime: number,
    retryCount: number
  ): DeliveryResult {
    return {
      digestId: digest.id,
      recipientEmail: digest.recipientEmail,
      deliveryStatus: 'failed',
      deliveryTimeMs: Date.now() - startTime,
      error,
      retryCount,
    };
  }

  /**
   * Generate plain text version from HTML
   *
   * Simple implementation that strips HTML tags and preserves basic structure
   */
  private generatePlainText(html: string): string {
    // Remove HTML tags
    let text = html
      .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '') // Remove style blocks
      .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '') // Remove script blocks
      .replace(/<br\s*\/?>/gi, '\n') // Convert <br> to newline
      .replace(/<\/p>/gi, '\n\n') // Convert </p> to double newline
      .replace(/<\/div>/gi, '\n') // Convert </div> to newline
      .replace(/<\/h[1-6]>/gi, '\n\n') // Convert </h*> to double newline
      .replace(/<[^>]+>/g, ''); // Remove all other tags

    // Decode HTML entities
    text = text
      .replace(/&nbsp;/g, ' ')
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'");

    // Normalize whitespace
    text = text.replace(/[ \t]+/g, ' '); // Multiple spaces to single space
    text = text.replace(/\n\s*\n\s*\n/g, '\n\n'); // Multiple newlines to double newline
    text = text.trim();

    return text;
  }

  /**
   * Get human-readable digest type label
   */
  private getDigestTypeLabel(digestType: string): string {
    switch (digestType) {
      case 'daily':
        return 'Daily Digest';
      case 'weekly':
        return 'Weekly Digest';
      case 'on_demand':
        return 'Email Digest';
      default:
        return 'Email Digest';
    }
  }

  /**
   * Sleep for specified milliseconds
   */
  private sleep(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }
}

