     2→ * Email Delivery Service (T047) - SMTP Implementation
     3→ *
     4→ * Handles SMTP email delivery with nodemailer:
     5→ * - SMTP connection configuration and verification
     6→ * - Email formatting (from, to, subject, HTML/plain text)
     7→ * - Delivery status tracking with retry logic
     8→ * - Error recovery and detailed error reporting
     9→ *
    10→ * Integrates with:
    11→ * - DigestGenerator (T046) for EmailDigest input
    12→ * - nodemailer for SMTP transport
    13→ */
    14→
    15→import nodemailer, { type Transporter, type SendMailOptions, type SentMessageInfo } from 'nodemailer';
    16→import type { EmailDigest } from '../types/email-digest';
    17→
    18→/**
    19→ * SMTP configuration for email delivery
    20→ */
    21→export interface SMTPConfig {
    22→  /** SMTP server hostname */
    23→  host: string;
    24→  /** SMTP server port (587 for TLS, 465 for SSL) */
    25→  port: number;
    26→  /** Use TLS/SSL connection */
    27→  secure: boolean;
    28→  /** Authentication credentials */
    29→  auth: {
    30→    /** SMTP username */
    31→    user: string;
    32→    /** SMTP password or app password */
    33→    pass: string;
    34→  };
    35→}
    36→
    37→/**
    38→ * Optional delivery configuration
    39→ */
    40→export interface DeliveryOptions {
    41→  /** Override recipient email address */
    42→  overrideRecipient?: string;
    43→  /** From email address (defaults to SMTP auth user) */
    44→  fromAddress?: string;
    45→  /** From display name */
    46→  fromName?: string;
    47→  /** Custom subject line (overrides generated subject) */
    48→  subject?: string;
    49→  /** Maximum retry attempts on failure */
    50→  maxRetries?: number;
    51→  /** Delay between retries in milliseconds */
    52→  retryDelayMs?: number;
    53→}
    54→
    55→/**
    56→ * Delivery result with status tracking
    57→ */
    58→export interface DeliveryResult {
    59→  /** Digest ID reference */
    60→  digestId: string;
    61→  /** Delivery timestamp (if successful) */
    62→  deliveredAt?: Date;
    63→  /** Recipient email address */
    64→  recipientEmail: string;
    65→  /** Delivery status */
    66→  deliveryStatus: 'sent' | 'failed';
    67→  /** SMTP message ID (if successful) */
    68→  messageId?: string;
    69→  /** Delivery time in milliseconds */
    70→  deliveryTimeMs: number;
    71→  /** Error message (if failed) */
    72→  error?: string;
    73→  /** Number of retry attempts made */
    74→  retryCount: number;
    75→}
    76→
    77→/**
    78→ * Email Delivery Service Implementation
    79→ *
    80→ * Provides SMTP email delivery for digest generation
    81→ */
    82→export class EmailDeliveryService {
    83→  private readonly transporter: Transporter;
    84→  private readonly config: SMTPConfig;
    85→  private readonly defaultFromAddress: string;
    86→
    87→  /**
    88→   * Initialize EmailDeliveryService with SMTP configuration
    89→   *
    90→   * @param config - SMTP server configuration
    91→   * @throws {Error} If SMTP configuration is invalid
    92→   */
    93→  constructor(config: SMTPConfig) {
    94→    this.validateConfig(config);
    95→    this.config = config;
    96→    this.defaultFromAddress = config.auth.user;
    97→
    98→    // Create nodemailer transporter
    99→    this.transporter = nodemailer.createTransport({
   100→      host: config.host,
   101→      port: config.port,
   102→      secure: config.secure,
   103→      auth: {
   104→        user: config.auth.user,
   105→        pass: config.auth.pass,
   106→      },
   107→    });
   108→  }
   109→
   110→  /**
   111→   * Verify SMTP connection
   112→   *
   113→   * @returns true if connection successful, false otherwise
   114→   */
   115→  async verifyConnection(): Promise<boolean> {
