/**
 * Unit Tests for EmailDeliveryService (T047) - TDD Approach
 *
 * Tests SMTP email delivery with nodemailer:
 * - SMTP connection configuration
 * - Email formatting (from, to, subject, HTML body)
 * - Delivery status tracking
 * - Error recovery and retries
 */

import { EmailDeliveryService, type DeliveryOptions } from '../../src/digest/email-delivery';
import type { EmailDigest } from '../../src/types/email-digest';
import type { Transporter } from 'nodemailer';

// Mock nodemailer
jest.mock('nodemailer');
import nodemailer from 'nodemailer';

describe('EmailDeliveryService', () => {
  let service: EmailDeliveryService;
  let mockTransporter: jest.Mocked<Transporter>;

  // Sample test data
  const sampleDigest: EmailDigest = {
    id: 'test-digest-123',
    generatedAt: new Date('2025-09-27T10:00:00Z'),
    digestType: 'daily',
    recipientEmail: 'test@example.com',
    categories: [
      {
        categoryName: 'Receipts',
        emailCount: 5,
        emails: [],
        priority: 1,
        templateData: {
          name: 'Receipts',
          displayName: 'Receipts',
          description: 'Purchase receipts and invoices',
          emailGroups: [],
          totalCount: 5,
          iconClass: 'receipt-icon',
          colorScheme: '#4CAF50',
          sortOrder: 1,
          statistics: {
            emailCount: 5,
            averageConfidence: 0.92,
            urgentEmailsCount: 0,
            aiClassifiedCount: 1,
            averageProcessingTime: 1500,
            topDomains: [{ domain: 'amazon.com', count: 3 }],
          },
          customVariables: {},
        },
        categoryMetadata: {
          averageConfidence: 0.92,
          processingDurationMs: 1500,
          aiClassificationUsed: true,
          urgencyDistribution: { high: 0, medium: 5, low: 0 },
        },
      },
    ],
    totalEmailCount: 5,
    dateRange: {
      start: new Date('2025-09-26T00:00:00Z'),
      end: new Date('2025-09-27T00:00:00Z'),
    },
    templateUsed: 'default-daily',
    htmlContent: '<html><body><h1>Daily Digest</h1><p>5 new emails</p></body></html>',
    deliveryStatus: 'pending',
    generationMetadata: {
      generationDurationMs: 245,
      templateRenderingTimeMs: 120,
      dataPreparationTimeMs: 85,
      templateEngine: 'handlebars',
      templateVersion: '1.0.0',
      partialsUsed: [],
      helpersUsed: [],
      emailsProcessed: 5,
      categoriesIncluded: 1,
      filteringRules: [],
      sortingCriteria: ['date'],
      memoryUsageMB: 45.2,
      cacheHitRate: 0.75,
      templateCacheUsed: true,
      contentQualityScore: 0.95,
      templateRenderingErrors: [],
      dataValidationWarnings: [],
    },
  };

  beforeEach(() => {
    // Reset mocks
    jest.clearAllMocks();

    // Create mock transporter
    mockTransporter = {
      sendMail: jest.fn(),
      verify: jest.fn(),
      close: jest.fn(),
    } as unknown as jest.Mocked<Transporter>;

    // Mock nodemailer.createTransport
    (nodemailer.createTransport as jest.Mock).mockReturnValue(mockTransporter);

    // Create service instance
    service = new EmailDeliveryService({
      host: 'smtp.test.com',
      port: 587,
      secure: false,
      auth: {
        user: 'test@example.com',
        pass: 'test-password',
      },
    });
  });

  afterEach(async () => {
    await service.close();
  });

  describe('Constructor and Configuration', () => {
    it('should create transporter with provided SMTP config', () => {
      expect(nodemailer.createTransport).toHaveBeenCalledWith({
        host: 'smtp.test.com',
        port: 587,
        secure: false,
        auth: {
          user: 'test@example.com',
          pass: 'test-password',
        },
      });
    });

    it('should create transporter with secure connection (port 465)', () => {
      new EmailDeliveryService({
        host: 'smtp.gmail.com',
        port: 465,
        secure: true,
        auth: {
          user: 'user@gmail.com',
          pass: 'app-password',
        },
      });

      expect(nodemailer.createTransport).toHaveBeenCalledWith({
        host: 'smtp.gmail.com',
        port: 465,
        secure: true,
        auth: {
          user: 'user@gmail.com',
          pass: 'app-password',
        },
      });
    });

    it('should throw error for invalid SMTP configuration', () => {
      expect(() => {
        new EmailDeliveryService({
          host: '',
          port: 587,
          secure: false,
          auth: {
            user: 'test@example.com',
            pass: 'password',
          },
        });
      }).toThrow('Invalid SMTP configuration: host is required');
    });
  });

  describe('verifyConnection', () => {
    it('should verify SMTP connection successfully', async () => {
      mockTransporter.verify.mockResolvedValue(true);

      const result = await service.verifyConnection();

      expect(result).toBe(true);
      expect(mockTransporter.verify).toHaveBeenCalled();
    });

    it('should return false on connection failure', async () => {
      mockTransporter.verify.mockRejectedValue(new Error('Connection refused'));

      const result = await service.verifyConnection();

      expect(result).toBe(false);
    });
  });

  describe('sendDigest', () => {
    it('should send digest email successfully', async () => {
      const mockInfo = {
        messageId: '<test-message-id@smtp.test.com>',
        accepted: ['test@example.com'],
        rejected: [],
        response: '250 OK',
      };

      mockTransporter.sendMail.mockResolvedValue(mockInfo);

      const result = await service.sendDigest(sampleDigest);

      expect(result.deliveryStatus).toBe('sent');
      expect(result.digestId).toBe('test-digest-123');
      expect(result.recipientEmail).toBe('test@example.com');
      expect(result.messageId).toBe('<test-message-id@smtp.test.com>');
      expect(result.deliveryTimeMs).toBeGreaterThan(0);
      expect(result.error).toBeUndefined();
      expect(result.retryCount).toBe(0);

      expect(mockTransporter.sendMail).toHaveBeenCalledWith({
        from: expect.any(String),
        to: 'test@example.com',
        subject: expect.stringContaining('Daily Digest'),
        html: sampleDigest.htmlContent,
        text: expect.any(String),
      });
    });

    it('should use custom delivery options', async () => {
      const mockInfo = {
        messageId: '<custom-message-id@smtp.test.com>',
        accepted: ['custom@example.com'],
        rejected: [],
        response: '250 OK',
      };

      mockTransporter.sendMail.mockResolvedValue(mockInfo);

      const options: DeliveryOptions = {
        overrideRecipient: 'custom@example.com',
        fromAddress: 'noreply@myapp.com',
        fromName: 'My App Digests',
        subject: 'Custom Subject Line',
      };

      const result = await service.sendDigest(sampleDigest, options);

      expect(result.recipientEmail).toBe('custom@example.com');

      expect(mockTransporter.sendMail).toHaveBeenCalledWith({
        from: '"My App Digests" <noreply@myapp.com>',
        to: 'custom@example.com',
        subject: 'Custom Subject Line',
        html: sampleDigest.htmlContent,
        text: expect.any(String),
      });
    });

    it('should generate plain text version from HTML', async () => {
      mockTransporter.sendMail.mockResolvedValue({
        messageId: '<msg@test.com>',
        accepted: ['test@example.com'],
        rejected: [],
        response: '250 OK',
      });

      await service.sendDigest(sampleDigest);

      const sendMailCall = mockTransporter.sendMail.mock.calls[0][0];
      expect(sendMailCall.text).toBeDefined();
      expect(sendMailCall.text).toContain('Daily Digest');
      expect(sendMailCall.text).toContain('5 new emails');
    });

    it('should handle delivery failure with error tracking', async () => {
      const smtpError = new Error('SMTP connection failed');
      mockTransporter.sendMail.mockRejectedValue(smtpError);

      const result = await service.sendDigest(sampleDigest);

      expect(result.deliveryStatus).toBe('failed');
      expect(result.digestId).toBe('test-digest-123');
      expect(result.error).toContain('SMTP connection failed');
      expect(result.messageId).toBeUndefined();
      expect(result.deliveryTimeMs).toBeGreaterThan(0);
    });

    it('should retry failed delivery up to max retries', async () => {
      const smtpError = new Error('Temporary failure');
      mockTransporter.sendMail
        .mockRejectedValueOnce(smtpError)
        .mockRejectedValueOnce(smtpError)
        .mockResolvedValue({
          messageId: '<success@test.com>',
          accepted: ['test@example.com'],
          rejected: [],
          response: '250 OK',
        });

      const options: DeliveryOptions = {
        maxRetries: 3,
        retryDelayMs: 10, // Short delay for testing
      };

      const result = await service.sendDigest(sampleDigest, options);

      expect(result.deliveryStatus).toBe('sent');
      expect(result.retryCount).toBe(2);
      expect(mockTransporter.sendMail).toHaveBeenCalledTimes(3);
    });

    it('should fail after exhausting retry attempts', async () => {
      const smtpError = new Error('Persistent failure');
      mockTransporter.sendMail.mockRejectedValue(smtpError);

      const options: DeliveryOptions = {
        maxRetries: 2,
        retryDelayMs: 10,
      };

      const result = await service.sendDigest(sampleDigest, options);

      expect(result.deliveryStatus).toBe('failed');
      expect(result.retryCount).toBe(2);
      expect(result.error).toContain('Persistent failure');
      expect(mockTransporter.sendMail).toHaveBeenCalledTimes(3); // Initial + 2 retries
    });
  });

  describe('sendTestEmail', () => {
    it('should send test email without actual delivery', async () => {
      const result = await service.sendTestEmail(sampleDigest);

      expect(result.deliveryStatus).toBe('sent');
      expect(result.messageId).toContain('test-mode');
      expect(result.digestId).toBe('test-digest-123');
      expect(mockTransporter.sendMail).not.toHaveBeenCalled();
    });

    it('should include test mode metadata in result', async () => {
      const result = await service.sendTestEmail(sampleDigest);

      expect(result.error).toContain('Test mode');
      expect(result.retryCount).toBe(0);
      expect(result.deliveryTimeMs).toBeGreaterThan(0);
    });
  });

  describe('formatSubject', () => {
    it('should format daily digest subject', () => {
      const subject = service.formatSubject(sampleDigest);

      expect(subject).toContain('Daily Digest');
      expect(subject).toContain('5');
      expect(subject).toMatch(/\d{4}-\d{2}-\d{2}/); // Date format
    });

    it('should format weekly digest subject', () => {
      const weeklyDigest = { ...sampleDigest, digestType: 'weekly' as const };
      const subject = service.formatSubject(weeklyDigest);

      expect(subject).toContain('Weekly Digest');
    });

    it('should format on_demand digest subject', () => {
      const onDemandDigest = { ...sampleDigest, digestType: 'on_demand' as const };
      const subject = service.formatSubject(onDemandDigest);

      expect(subject).toContain('Email Digest');
    });

    it('should include urgent email count in subject when present', () => {
      const urgentDigest: EmailDigest = {
        ...sampleDigest,
        categories: [
          {
            ...sampleDigest.categories[0],
            categoryMetadata: {
              ...sampleDigest.categories[0].categoryMetadata,
              urgencyDistribution: { high: 3, medium: 2, low: 0 },
            },
          },
        ],
      };

      const subject = service.formatSubject(urgentDigest);

      expect(subject).toContain('3 urgent');
    });
  });

  describe('close', () => {
    it('should close SMTP connection', async () => {
      await service.close();

      expect(mockTransporter.close).toHaveBeenCalled();
    });

    it('should handle close errors gracefully', async () => {
      // Make close throw an error synchronously
      mockTransporter.close.mockImplementationOnce(() => {
        throw new Error('Close failed');
      });

      // Should not throw - error is caught internally
      await expect(service.close()).resolves.not.toThrow();
    });
  });

  describe('Error Handling', () => {
    it('should handle invalid recipient email', async () => {
      const invalidDigest = { ...sampleDigest, recipientEmail: 'invalid-email' };

      const result = await service.sendDigest(invalidDigest);

      expect(result.deliveryStatus).toBe('failed');
      expect(result.error).toContain('Invalid recipient email');
    });

    it('should handle missing HTML content', async () => {
      const emptyDigest = { ...sampleDigest, htmlContent: '' };

      const result = await service.sendDigest(emptyDigest);

      expect(result.deliveryStatus).toBe('failed');
      expect(result.error).toContain('HTML content is required');
    });

    it('should handle SMTP authentication failure', async () => {
      const authError = new Error('535 Authentication failed');
      mockTransporter.sendMail.mockRejectedValue(authError);

      const result = await service.sendDigest(sampleDigest);

      expect(result.deliveryStatus).toBe('failed');
      expect(result.error).toContain('Authentication failed');
    });

    it('should handle rate limit errors', async () => {
      const rateLimitError = new Error('421 Rate limit exceeded');
      mockTransporter.sendMail.mockRejectedValue(rateLimitError);

      const result = await service.sendDigest(sampleDigest);

      expect(result.deliveryStatus).toBe('failed');
      expect(result.error).toContain('Rate limit exceeded');
    });
  });

  describe('Delivery Tracking', () => {
    it('should track delivery timing accurately', async () => {
      mockTransporter.sendMail.mockImplementation(
        () =>
          new Promise((resolve) =>
            setTimeout(
              () =>
                resolve({
                  messageId: '<msg@test.com>',
                  accepted: ['test@example.com'],
                  rejected: [],
                  response: '250 OK',
                }),
              50
            )
          )
      );

      const result = await service.sendDigest(sampleDigest);

      expect(result.deliveryTimeMs).toBeGreaterThanOrEqual(50);
      expect(result.deliveryTimeMs).toBeLessThan(200); // Reasonable upper bound
    });

    it('should include delivered timestamp on success', async () => {
      mockTransporter.sendMail.mockResolvedValue({
        messageId: '<msg@test.com>',
        accepted: ['test@example.com'],
        rejected: [],
        response: '250 OK',
      });

      const beforeSend = Date.now();
      const result = await service.sendDigest(sampleDigest);
      const afterSend = Date.now();

      expect(result.deliveredAt).toBeDefined();
      expect(result.deliveredAt!.getTime()).toBeGreaterThanOrEqual(beforeSend);
      expect(result.deliveredAt!.getTime()).toBeLessThanOrEqual(afterSend);
    });

    it('should not include delivered timestamp on failure', async () => {
      mockTransporter.sendMail.mockRejectedValue(new Error('Delivery failed'));

      const result = await service.sendDigest(sampleDigest);

      expect(result.deliveredAt).toBeUndefined();
    });
  });
});

