/**
 * EmailDigest entity with template data
 *
 * New entities for HTML email digest generation using Handlebars templates
 * with category grouping and enhanced delivery tracking.
 */

export interface EmailDigest {
  id: string; // UUID
  generatedAt: Date;
  digestType: 'daily' | 'weekly' | 'on_demand';
  recipientEmail: string;

  // Content structure
  categories: DigestCategory[];
  totalEmailCount: number;
  dateRange: {
    start: Date;
    end: Date;
  };

  // Template and delivery
  templateUsed: string;
  htmlContent: string;
  deliveryStatus: 'pending' | 'sent' | 'failed';
  deliveredAt?: Date;
  deliveryError?: string;

  // Enhanced digest metadata
  generationMetadata: DigestGenerationMetadata;
  deliveryMetadata?: DigestDeliveryMetadata;
}

export interface DigestCategory {
  categoryName: string;
  emailCount: number;
  emails: DigestEmail[];
  priority: number; // Display order

  // Template data for Handlebars
  templateData: DigestCategoryTemplateData;
  customSummary?: string; // Optional human-readable summary

  // Category-specific metadata
  categoryMetadata: {
    averageConfidence: number;
    processingDurationMs: number;
    aiClassificationUsed: boolean;
    urgencyDistribution: Record<string, number>;
  };
}

export interface DigestEmail {
  emailId: string;
  subject: string;
  from: string;
  date: Date;
  snippet: string; // First 150 chars of body

  // Classification metadata
  confidence: number;
  categories: string[];
  urgency: string;

  // Digest-specific rendering data
  includeFullContent: boolean;
  customHighlights: string[]; // Key extracted information
  renderingData: DigestEmailRenderingData;
}

/**
 * Template data structure for Handlebars rendering
 */
export interface DigestCategoryTemplateData {
  // Basic category information
  name: string;
  displayName: string;
  description: string;

  // Email organization
  emailGroups: EmailGroup[];
  totalCount: number;

  // Visual presentation
  iconClass: string;
  colorScheme: string;
  sortOrder: number;

  // Summary statistics
  statistics: CategoryStatistics;

  // Custom template variables
  customVariables: Record<string, unknown>;
}

export interface EmailGroup {
  groupType: 'urgent' | 'normal' | 'low_priority' | 'follow_up';
  groupName: string;
  emails: DigestEmail[];
  groupSummary: string;
  groupIcon?: string;
}

export interface CategoryStatistics {
  emailCount: number;
  averageConfidence: number;
  urgentEmailsCount: number;
  aiClassifiedCount: number;
  averageProcessingTime: number;
  topDomains: Array<{
    domain: string;
    count: number;
  }>;
}

/**
 * Email-specific rendering data for digest templates
 */
export interface DigestEmailRenderingData {
  // Display formatting
  displaySubject: string; // Truncated/formatted subject
  displayFrom: string; // Formatted sender name
  displayDate: string; // Human-readable date
  displayTime: string; // Time portion

  // Content presentation
  summarySnippet: string; // Formatted snippet
  keyHighlights: string[]; // Important extracted info
  actionableItems: ActionableItem[];

  // Visual elements
  urgencyIcon: string;
  confidenceIndicator: string;
  categoryBadges: CategoryBadge[];

  // Interactive elements
  quickActions: QuickAction[];
  expandedContentAvailable: boolean;
}

export interface ActionableItem {
  type: 'deadline' | 'follow_up' | 'response_required' | 'review' | 'payment';
  description: string;
  dueDate?: Date;
  priority: 'low' | 'medium' | 'high';
  estimatedEffort: string; // e.g., "5 minutes", "review required"
}

export interface CategoryBadge {
  category: string;
  displayName: string;
  confidence: number;
  badgeColor: string;
  isSecondary: boolean;
}

export interface QuickAction {
  actionType: 'mark_read' | 'archive' | 'flag' | 'forward' | 'reply' | 'schedule';
  actionLabel: string;
  actionUrl: string;
  iconClass: string;
}

/**
 * Digest generation metadata for performance and debugging
 */
export interface DigestGenerationMetadata {
  generationDurationMs: number;
  templateRenderingTimeMs: number;
  dataPreparationTimeMs: number;

  // Template processing
  templateEngine: 'handlebars';
  templateVersion: string;
  partialsUsed: string[];
  helpersUsed: string[];

  // Data processing
  emailsProcessed: number;
  categoriesIncluded: number;
  filteringRules: string[];
  sortingCriteria: string[];

  // Performance metrics
  memoryUsageMB: number;
  cacheHitRate: number;
  templateCacheUsed: boolean;

  // Quality metrics
  contentQualityScore: number; // How well the digest represents the data
  templateRenderingErrors: string[];
  dataValidationWarnings: string[];
}

/**
 * Delivery metadata for SMTP and tracking
 */
export interface DigestDeliveryMetadata {
  deliveryAttempts: DeliveryAttempt[];
  smtpConfiguration: {
    server: string;
    port: number;
    security: 'tls' | 'ssl' | 'none';
    authenticationUsed: boolean;
  };

  // Delivery tracking
  messageId: string; // SMTP message ID
  deliveryReceipt?: string;
  readReceipt?: boolean;
  bounceHandling: BounceHandlingInfo;

  // Performance
  deliveryDurationMs: number;
  retryPolicy: RetryPolicyInfo;

  // Content validation
  htmlValidation: HtmlValidationResult;
  antispamScore?: number;
  deliverabilityCheck: DeliverabilityCheck;
}

export interface DeliveryAttempt {
  attemptNumber: number;
  attemptedAt: Date;
  status: 'success' | 'failed' | 'retrying';
  errorMessage?: string;
  smtpResponse?: string;
  durationMs: number;
}

export interface BounceHandlingInfo {
  bounceTrackingEnabled: boolean;
  bounceAddress: string;
  bounceCategorization: string[];
  automaticRetryEnabled: boolean;
}

export interface RetryPolicyInfo {
  maxRetries: number;
  retryIntervalMs: number;
  exponentialBackoff: boolean;
  retryConditions: string[];
}

export interface HtmlValidationResult {
  isValid: boolean;
  validationErrors: string[];
  validationWarnings: string[];
  htmlSize: number;
  imageCount: number;
  linkCount: number;
  accessibilityScore: number;
}

export interface DeliverabilityCheck {
  spamScore: number;
  dkimValidation: boolean;
  spfValidation: boolean;
  dmarcCompliance: boolean;
  reputation: 'good' | 'neutral' | 'poor';
  recommendations: string[];
}

/**
 * Enhanced digest with comprehensive analytics
 */
export interface AnalyticsDigest extends EmailDigest {
  analytics: DigestAnalytics;
  userEngagement?: UserEngagementMetrics;
  feedbackData?: DigestFeedback[];
}

export interface DigestAnalytics {
  // Content analysis
  contentDistribution: Record<string, number>;
  urgencyDistribution: Record<string, number>;
  domainDistribution: Record<string, number>;

  // Classification analysis
  classificationAccuracyEstimate: number;
  aiRoutingFrequency: number;
  averageConfidenceScore: number;

  // Temporal analysis
  emailTimingPatterns: TemporalPattern[];
  seasonalAdjustments: SeasonalAdjustment[];

  // Quality metrics
  digestQualityScore: number;
  contentRelevanceScore: number;
  userSatisfactionPrediction: number;
}

export interface UserEngagementMetrics {
  openRate: number;
  clickThroughRate: number;
  timeSpentReading: number;
  actionsPerformed: number;
  feedbackProvided: boolean;
  digestPreferences: DigestPreferences;
}

export interface DigestFeedback {
  feedbackType: 'rating' | 'correction' | 'preference' | 'bug_report';
  feedbackValue: unknown;
  providedAt: Date;
  feedbackText?: string;
  processed: boolean;
}

export interface DigestPreferences {
  frequency: 'daily' | 'weekly' | 'on_demand';
  categoriesIncluded: string[];
  categoriesExcluded: string[];
  urgencyFilter: 'all' | 'high_only' | 'medium_and_high';
  maxEmailsPerCategory: number;
  includeFullContent: boolean;
  deliveryTime: string; // "09:00" format
  timeZone: string;
}

export interface TemporalPattern {
  patternType: 'peak_hours' | 'quiet_periods' | 'weekly_cycles' | 'seasonal';
  patternData: Record<string, number>;
  confidence: number;
  description: string;
}

export interface SeasonalAdjustment {
  period: 'daily' | 'weekly' | 'monthly' | 'yearly';
  adjustmentFactor: number;
  reason: string;
  validFrom: Date;
  validTo?: Date;
}

