+
+  /**
+   * Send test email without actual delivery (preview mode)
+   *
+   * @param digest - Email digest to preview
+   * @returns Delivery result indicating test mode
+   */
+  async sendTestEmail(digest: EmailDigest): Promise<DeliveryResult> {
+    const startTime = Date.now();
+
+    // Simulate processing delay
+    await this.sleep(10);
+
+    const deliveryTimeMs = Date.now() - startTime;
+
+    return {
+      digestId: digest.id,
+      deliveredAt: new Date(),
+      recipientEmail: digest.recipientEmail,
+      deliveryStatus: 'sent',
+      messageId: `<test-mode-${digest.id}@localhost>`,
+      deliveryTimeMs,
+      error: 'Test mode - email not actually sent',
+      retryCount: 0,
+    };
+  }
+
+  /**
+   * Format subject line for digest email
+   *
+   * @param digest - Email digest
+   * @returns Formatted subject line
+   */
+  formatSubject(digest: EmailDigest): string {
+    const digestTypeLabel = this.getDigestTypeLabel(digest.digestType);
+    const totalEmails = digest.totalEmailCount;
+    const dateStr = digest.generatedAt.toISOString().split('T')[0]; // YYYY-MM-DD
+
+    // Count urgent emails
+    const urgentCount = digest.categories.reduce((sum, cat) => sum + cat.categoryMetadata.urgencyDistribution.high, 0);
+
+    const urgentSuffix = urgentCount > 0 ? ` (${urgentCount} urgent)` : '';
+
+    return `${digestTypeLabel} - ${totalEmails} email${totalEmails === 1 ? '' : 's'}${urgentSuffix} - ${dateStr}`;
+  }
+
+  /**
+   * Close SMTP connection
+   */
+  async close(): Promise<void> {
+    try {
+      this.transporter.close();
+    } catch {
+      // Ignore close errors
+    }
+  }
+
+  /**
+   * Validate SMTP configuration
+   */
+  private validateConfig(config: SMTPConfig): void {
+    if (!config.host || config.host.trim() === '') {
+      throw new Error('Invalid SMTP configuration: host is required');
+    }
+
+    if (!config.port || config.port < 1 || config.port > 65535) {
+      throw new Error('Invalid SMTP configuration: port must be between 1 and 65535');
+    }
+
+    if (!config.auth || !config.auth.user || !config.auth.pass) {
+      throw new Error('Invalid SMTP configuration: auth credentials are required');
+    }
+  }
+
+  /**
+   * Validate digest content before sending
+   */
+  private validateDigest(digest: EmailDigest): string | null {
+    // Validate recipient email format
+    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
+    if (!emailRegex.test(digest.recipientEmail)) {
+      return 'Invalid recipient email format';
+    }
+
+    // Validate HTML content
+    if (!digest.htmlContent || digest.htmlContent.trim() === '') {
+      return 'HTML content is required';
+    }
+
+    return null;
+  }
+
+  /**
+   * Create failed delivery result
+   */
+  private createFailedResult(
+    digest: EmailDigest,
+    error: string,
+    startTime: number,
+    retryCount: number
+  ): DeliveryResult {
+    return {
+      digestId: digest.id,
+      recipientEmail: digest.recipientEmail,
+      deliveryStatus: 'failed',
+      deliveryTimeMs: Date.now() - startTime,
+      error,
+      retryCount,
+    };
+  }
+
+  /**
+   * Generate plain text version from HTML
+   *
+   * Simple implementation that strips HTML tags and preserves basic structure
+   */
+  private generatePlainText(html: string): string {
+    // Remove HTML tags
+    let text = html
+      .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '') // Remove style blocks
+      .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '') // Remove script blocks
+      .replace(/<br\s*\/?>/gi, '\n') // Convert <br> to newline
+      .replace(/<\/p>/gi, '\n\n') // Convert </p> to double newline
+      .replace(/<\/div>/gi, '\n') // Convert </div> to newline
+      .replace(/<\/h[1-6]>/gi, '\n\n') // Convert </h*> to double newline
+      .replace(/<[^>]+>/g, ''); // Remove all other tags
+
+    // Decode HTML entities
+    text = text
+      .replace(/&nbsp;/g, ' ')
+      .replace(/&amp;/g, '&')
+      .replace(/&lt;/g, '<')
+      .replace(/&gt;/g, '>')
+      .replace(/&quot;/g, '"')
+      .replace(/&#39;/g, "'");
+
+    // Normalize whitespace
+    text = text.replace(/[ \t]+/g, ' '); // Multiple spaces to single space
+    text = text.replace(/\n\s*\n\s*\n/g, '\n\n'); // Multiple newlines to double newline
+    text = text.trim();
+
+    return text;
+  }
+
+  /**
+   * Get human-readable digest type label
+   */
+  private getDigestTypeLabel(digestType: string): string {
+    switch (digestType) {
+      case 'daily':
+        return 'Daily Digest';
+      case 'weekly':
+        return 'Weekly Digest';
+      case 'on_demand':
+        return 'Email Digest';
+      default:
+        return 'Email Digest';
+    }
+  }
+
+  /**
+   * Sleep for specified milliseconds
+   */
+  private sleep(ms: number): Promise<void> {
+    return new Promise((resolve) => setTimeout(resolve, ms));
+  }
+}
